  1→import React, { useState, useEffect, useRef, useCallback } from 'react';
  2→import { useNavigate, useParams, useLocation } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useChapter, useChapterCommentCounts } from '../hooks/useStoryData';
  5→import { saveReadingProgress, getReadingProgress } from '../../../../API/StoryApi';
  6→import { useQueryClient } from '@tanstack/react-query';
  7→import { motion, AnimatePresence } from 'framer-motion';
  8→import { BeatLoader } from 'react-spinners';
  9→import ParagraphCommentLayer from './ParagraphCommentLayer';
 10→import CommentPanel from './CommentPanel';
 11→
 12→import { LexicalComposer } from '@lexical/react/LexicalComposer';
 13→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
 14→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 15→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
 16→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 17→import { VIEWER_NODES, EDITOR_THEME } from '../../HomePage/Editor/editorConfig';
 18→
 19→import './ChapterReader.css';
 20→
 21→
 22→const ReaderContent = ({ chapter, onContentReady }) => {
 23→    const [editor] = useLexicalComposerContext();
 24→
 25→    useEffect(() => {
 26→        if (chapter?.content && editor) {
 27→            try {
 28→                const content = typeof chapter.content === 'string'
 29→                    ? chapter.content
 30→                    : JSON.stringify(chapter.content);
 31→                const state = editor.parseEditorState(content);
 32→                editor.setEditorState(state);
 33→            } catch (err) {
 34→                console.error('Failed to load chapter content:', err);
 35→            }
 36→            editor.setEditable(false);
 37→            // Wait for Lexical's DOM reconciliation + browser paint before signaling ready
 38→            const removeListener = editor.registerUpdateListener(() => {
 39→                removeListener();
 40→                requestAnimationFrame(() => {
 41→                    if (onContentReady) onContentReady();
 42→                });
 43→            });
 44→        }
 45→    }, [chapter?.id, editor]);
 46→
 47→    return (
 48→        <RichTextPlugin
 49→            contentEditable={<ContentEditable className="chapter-reader-content" />}
 50→            ErrorBoundary={LexicalErrorBoundary}
 51→        />
 52→    );
 53→};
 54→
 55→const ChapterReader = () => {
 56→    const { storyId, chapterId } = useParams();
 57→    const navigate = useNavigate();
 58→    const location = useLocation();
 59→    const { session } = useAuth();
 60→    const token = session?.access_token;
 61→
 62→    const queryClient = useQueryClient();
 63→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 64→    const { data: commentCounts } = useChapterCommentCounts(chapterId, token);
 65→    const progressTimerRef = useRef(null);
 66→    const scrollRef = useRef(0);
 67→    const bodyRef = useRef(null);
 68→    const hasRestoredRef = useRef(false);
 69→
 70→    // The scrollable element is .home-parent-container, not the window
 71→    const getScrollContainer = useCallback(() =>
 72→        document.querySelector('.home-parent-container') || document.documentElement
 73→    , []);
 74→    const [contentReady, setContentReady] = useState(false);
 75→    const [activeComment, setActiveComment] = useState(null);
 76→
 77→    // Save reading progress debounced on scroll
 78→    const saveProgress = useCallback(() => {
 79→        if (!token || !storyId || !chapterId) return Promise.resolve();
 80→        return saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 81→    }, [token, storyId, chapterId]);
 82→
 83→    useEffect(() => {
 84→        const container = getScrollContainer();
 85→
 86→        const handleScroll = () => {
 87→            const scrollTop = container.scrollTop;
 88→            const scrollableHeight = container.scrollHeight - container.clientHeight;
 89→            scrollRef.current = scrollableHeight > 0 ? Math.min(scrollTop / scrollableHeight, 1) : 0;
 90→
 91→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 92→            progressTimerRef.current = setTimeout(saveProgress, 3000);
 93→        };
 94→
 95→        container.addEventListener('scroll', handleScroll, { passive: true });
 96→        return () => {
 97→            container.removeEventListener('scroll', handleScroll);
 98→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 99→            // Save on unmount, then invalidate story cache so StoryDetail gets fresh progress
100→            saveProgress().then(() => {
101→                queryClient.invalidateQueries({ queryKey: ['story', storyId] });
102→            });
103→        };
104→    }, [saveProgress, getScrollContainer, queryClient, storyId]);
105→
106→    // Restore scroll position — from location.state or by fetching saved progress
107→    useEffect(() => {
108→        if (hasRestoredRef.current || !contentReady) return;
109→        hasRestoredRef.current = true;
110→
111→        const restoreScroll = (position) => {
112→            if (!position || position <= 0) return;
113→            const container = getScrollContainer();
114→            let lastHeight = -1;
115→
116→            const attemptScroll = (retries = 0) => {
117→                setTimeout(() => {
118→                    const scrollableHeight = container.scrollHeight - container.clientHeight;
119→                    if (scrollableHeight <= 0 && retries < 10) {
120→                        attemptScroll(retries + 1);
121→                        return;
122→                    }
123→                    // Wait until height stabilizes (same value twice in a row)
124→                    if (scrollableHeight !== lastHeight && retries < 10) {
125→                        lastHeight = scrollableHeight;
126→                        attemptScroll(retries + 1);
127→                        return;
128→                    }
129→                    if (scrollableHeight > 0) {
130→                        container.scrollTo({ top: scrollableHeight * position, behavior: 'instant' });
131→                    }
132→                    navigate(location.pathname, { replace: true, state: {} });
133→                }, 50);
134→            };
135→            attemptScroll();
136→        };
137→
138→        const statePosition = location.state?.scrollPosition;
139→        if (statePosition) {
140→            restoreScroll(statePosition);
141→        } else if (token) {
142→            // No position passed via navigation state — fetch saved progress
143→            getReadingProgress(token, storyId).then(progress => {
144→                if (progress?.chapter_id === chapterId && progress.scroll_position > 0) {
145→                    restoreScroll(progress.scroll_position);
146→                }
147→            }).catch(() => {});
148→        }
149→    }, [contentReady]);
150→
151→    // Reset state when chapter changes
152→    useEffect(() => {
153→        setContentReady(false);
154→        setActiveComment(null);
155→        hasRestoredRef.current = false;
156→    }, [chapterId]);
157→
158→    // Scroll progress bar (re-runs when chapter loads so the bar element exists in the DOM)
159→    useEffect(() => {
160→        const bar = document.getElementById('chapter-progress-bar');
161→        if (!bar) return;
162→        const container = getScrollContainer();
163→
164→        const updateBar = () => {
165→            const scrollTop = container.scrollTop;
166→            const scrollableHeight = container.scrollHeight - container.clientHeight;
167→            const pct = scrollableHeight > 0 ? (scrollTop / scrollableHeight) * 100 : 0;
168→            bar.style.width = `${Math.min(pct, 100)}%`;
169→        };
170→
171→        container.addEventListener('scroll', updateBar, { passive: true });
172→        return () => container.removeEventListener('scroll', updateBar);
173→    }, [getScrollContainer, isLoading]);
174→
175→    const editorConfig = {
176→        namespace: 'ChapterReader',
177→        theme: EDITOR_THEME,
178→        nodes: VIEWER_NODES,
179→        editable: false,
180→        onError(error) { console.error('Lexical error:', error); },
181→    };
182→
183→    if (isLoading) {
184→        return (
185→            <div className="chapter-reader">
186→                <div className="chapter-reader-loading">
187→                    <BeatLoader size={10} color="var(--text-muted)" />
188→                </div>
189→            </div>
190→        );
191→    }
192→
193→    if (!chapter) {
194→        return (
195→            <div className="chapter-reader">
196→                <p className="chapter-reader-error">Chapter not found.</p>
197→            </div>
198→        );
199→    }
200→
201→    const prevCh = chapter.prev_chapter;
202→    const nextCh = chapter.next_chapter;
203→
204→    return (
205→        <>
206→        {/* Progress bar — must be outside motion.div so position:fixed works */}
207→        <div className="chapter-progress-track">
208→            <div id="chapter-progress-bar" className="chapter-progress-fill" />
209→        </div>
210→
211→        <motion.div
212→            className="chapter-reader"
213→            initial={{ opacity: 0 }}
214→            animate={{ opacity: 1 }}
215→            transition={{ duration: 0.2 }}
216→        >
217→            {/* Header */}
218→            <div className="chapter-reader-header">
219→                <button
220→                    className="chapter-reader-back"
221→                    onClick={() => navigate(`/home/stories/${storyId}`)}
222→                >
223→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
224→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
225→                    </svg>
226→                </button>
227→                <div className="chapter-reader-header-info">
228→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
229→                    <h1 className="chapter-reader-title">{chapter.title}</h1>
230→                </div>
231→            </div>
232→
233→            {/* Content */}
234→            <div className="chapter-reader-body" ref={bodyRef}>
235→                <LexicalComposer initialConfig={editorConfig}>
236→                    <ReaderContent chapter={chapter} onContentReady={() => setContentReady(true)} />
237→                </LexicalComposer>
238→                <ParagraphCommentLayer
239→                    containerRef={bodyRef}
240→                    commentCounts={commentCounts}
241→                    onParagraphClick={setActiveComment}
242→                />
243→            </div>
244→
245→            {/* Comment Panel */}
246→            <AnimatePresence>
247→                {activeComment && (
248→                    <CommentPanel
249→                        chapterId={chapterId}
250→                        activeComment={activeComment}
251→                        onClose={() => setActiveComment(null)}
252→                    />
253→                )}
254→            </AnimatePresence>
255→
256→            {/* Navigation */}
257→            <div className="chapter-reader-nav">
258→                {prevCh ? (
259→                    <button
260→                        className="chapter-nav-btn chapter-nav-prev"
261→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
262→                    >
263→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
264→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
265→                        </svg>
266→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
267→                    </button>
268→                ) : <div />}
269→                {nextCh ? (
270→                    <button
271→                        className="chapter-nav-btn chapter-nav-next"
272→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
273→                    >
274→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
275→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
276→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
277→                        </svg>
278→                    </button>
279→                ) : <div />}
280→            </div>
281→        </motion.div>
282→        </>
283→    );
284→};
285→
286→export default ChapterReader;
