  1→import { publicGet, authedGet, authedJsonRequest, authedFormRequest } from "./apiHelpers";
  2→
  3→// ── Stories ──
  4→
  5→export const createStory = (token, formData) =>
  6→    authedFormRequest(token, 'POST', '/stories', formData, 'failed to create story');
  7→
  8→export const getStories = (limit = 10, before = null, status = null, tag = null, token = null) => {
  9→    const params = new URLSearchParams({ limit: String(limit) });
 10→    if (before) params.set('before', before);
 11→    if (status) params.set('status', status);
 12→    if (tag) params.set('tag', tag);
 13→    return token
 14→        ? authedGet(token, `/stories?${params}`, 'failed to fetch stories')
 15→        : publicGet(`/stories?${params}`, 'failed to fetch stories');
 16→};
 17→
 18→export const getStoryById = (storyId, token = null) =>
 19→    token
 20→        ? authedGet(token, `/stories/${storyId}`, 'failed to fetch story')
 21→        : publicGet(`/stories/${storyId}`, 'failed to fetch story');
 22→
 23→export const updateStory = (token, storyId, formData) =>
 24→    authedFormRequest(token, 'PATCH', `/stories/${storyId}`, formData, 'failed to update story');
 25→
 26→export const deleteStory = (token, storyId) =>
 27→    authedFormRequest(token, 'DELETE', `/stories/${storyId}`, undefined, 'failed to delete story');
 28→
 29→export const getMyStories = (token, limit = 5, before = null) => {
