 48→
 49→// ── Chapters ──
 50→
 51→export const createChapter = (token, storyId, title) =>
 52→    authedJsonRequest(token, 'POST', `/stories/${storyId}/chapters`, { title }, 'failed to create chapter');
 53→
 54→export const getChapter = (storyId, chapterId, token = null) =>
 55→    token
 56→        ? authedGet(token, `/stories/${storyId}/chapters/${chapterId}`, 'failed to fetch chapter')
 57→        : publicGet(`/stories/${storyId}/chapters/${chapterId}`, 'failed to fetch chapter');
