 59→export const updateChapter = (token, storyId, chapterId, data) =>
 60→    authedJsonRequest(token, 'PATCH', `/stories/${storyId}/chapters/${chapterId}`, data, 'failed to update chapter');
 61→
 62→export const deleteChapter = (token, storyId, chapterId) =>
 63→    authedFormRequest(token, 'DELETE', `/stories/${storyId}/chapters/${chapterId}`, undefined, 'failed to delete chapter');
 64→
 65→export const reorderChapters = (token, storyId, chapterOrder) =>
 66→    authedJsonRequest(token, 'POST', `/stories/${storyId}/chapters/reorder`, { chapterOrder }, 'failed to reorder chapters');
 67→
 68→// ── Interactions ──
 69→
 70→export const toggleStoryVote = (token, storyId) =>
 71→    authedFormRequest(token, 'POST', `/stories/${storyId}/vote`, undefined, 'failed to toggle vote');
 72→
 73→export const toggleStoryLibrary = (token, storyId) =>
