 75→
 76→export const getChapterComments = (chapterId, paragraphIndex = null, token = null) => {
 77→    const params = new URLSearchParams();
 78→    if (paragraphIndex !== null && paragraphIndex !== undefined) {
 79→        params.set('paragraph_index', paragraphIndex);
 80→    }
 81→    const qs = params.toString();
 82→    const path = `/chapters/${chapterId}/comments${qs ? '?' + qs : ''}`;
 83→    return token
 84→        ? authedGet(token, path, 'failed to fetch comments')
 85→        : publicGet(path, 'failed to fetch comments');
 86→};
 87→
 88→export const getChapterCommentCounts = (chapterId, token = null) =>
