249→export const getCommentCountsService = async (chapterId) => {
250→    if (!chapterId) {
251→        throw { status: 400, error: 'chapterId is required' };
252→    }
253→
254→    const { data, error } = await supabase
255→        .from('story_comments')
256→        .select('paragraph_index')
257→        .eq('chapter_id', chapterId)
258→        .neq('paragraph_index', -1);
259→
260→    if (error) {
261→        console.error('supabase error fetching comment counts:', error.message);
262→        throw { status: 500, error: 'failed to fetch comment counts' };
263→    }
264→
265→    // Aggregate counts per paragraph_index
266→    const counts = {};
267→    (data || []).forEach(row => {
268→        const idx = row.paragraph_index;
269→        counts[idx] = (counts[idx] || 0) + 1;
270→    });
271→
272→    return counts;
273→};
