275→export const addCommentService = async (chapterId, userId, comment, paragraphIndex, paragraphFingerprint, parentId) => {
276→    if (!chapterId || !userId) {
277→        throw { status: 400, error: 'chapterId and userId are required' };
278→    }
279→    if (!comment || typeof comment !== 'string' || comment.trim().length === 0) {
280→        throw { status: 400, error: 'comment is required' };
281→    }
282→    if (comment.length > 300) {
283→        throw { status: 400, error: 'comment must be 300 characters or less' };
284→    }
285→
286→    const insertData = {
287→        chapter_id: chapterId,
288→        user_id: userId,
289→        comment: comment.trim(),
290→        paragraph_index: paragraphIndex !== undefined ? parseInt(paragraphIndex) : -1,
291→        paragraph_fingerprint: paragraphFingerprint || null,
292→        parent_id: parentId || null,
293→    };
294→
295→    const { data, error } = await supabase
296→        .from('story_comments')
297→        .insert(insertData)
298→        .select(`*, users(id, name, image_url, username, badge)`)
299→        .single();
300→
301→    if (error) {
302→        console.error('supabase error adding comment:', error.message);
303→        throw { status: 500, error: 'failed to add comment' };
304→    }
305→
306→    return data;
307→};
