 41→const decorateStoryMedia = (story, usage = 'card') => {
 42→    if(!story){
 43→        return story;
 44→    }
 45→
 46→    const coverMedia = createMediaResponsePayload('story-covers', story.cover_url, usage);
 47→    return {
 48→        ...story,
 49→        cover_url: coverMedia?.preferred_url || story.cover_url || null,
 50→        cover_media: coverMedia
 51→    };
