 54→/**
 55→ * Batch-fetch public user profiles for a list of author IDs.
 56→ */
 57→const fetchAuthorProfiles = async (authorIds) => {
 58→    const unique = [...new Set(authorIds.filter(Boolean))];
 59→    if (unique.length === 0) return {};
 60→
 61→    const { data, error } = await supabase
 62→        .from('users')
 63→        .select('id, name, image_url, username, badge')
 64→        .in('id', unique);
 65→
 66→    if (error) {
 67→        console.error('supabase error fetching author profiles:', error.message);
 68→        return {};
 69→    }
 70→
 71→    const map = {};
 72→    (data || []).forEach(u => { map[u.id] = decorateAuthorSummary(u, 'card'); });
 73→    return map;
 74→};
