351→export const deleteStoryService = async (storyId, userId) => {
352→    if (!storyId || !userId) {
353→        throw { status: 400, error: 'storyId and userId are required' };
354→    }
355→
356→    const { data: existing, error: fetchError } = await supabase
357→        .from('stories')
358→        .select('author_id')
359→        .eq('id', storyId)
360→        .single();
361→
362→    if (fetchError || !existing) {
363→        throw { status: 404, error: 'story not found' };
364→    }
365→    if (existing.author_id !== userId) {
366→        throw { status: 403, error: 'not authorized to delete this story' };
367→    }
368→
369→    const { error } = await supabase
370→        .from('stories')
371→        .delete()
372→        .eq('id', storyId);
373→
374→    if (error) {
375→        console.error('supabase error deleting story:', error.message);
376→        throw { status: 500, error: 'failed to delete story' };
377→    }
378→
379→    return { message: 'story deleted' };
380→};
