382→export const getMyStoriesService = async (userId, limit, before) => {
383→    if (!userId) {
384→        throw { status: 400, error: 'userId is required' };
385→    }
386→
387→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 5, 1), 20);
388→
389→    let query = supabase
390→        .from('stories')
391→        .select(`${STORY_SELECT_COLUMNS}, chapters(id, chapter_number, title, status, word_count)`)
392→        .eq('author_id', userId)
393→        .order('updated_at', { ascending: false })
394→        .limit(parsedLimit + 1);
395→
396→    if (before) {
397→        query = query.lt('updated_at', before);
398→    }
399→
400→    const { data, error } = await query;
401→
402→    if (error) {
403→        console.error('supabase error fetching my stories:', error.message);
404→        throw { status: 500, error: 'failed to fetch stories' };
405→    }
406→
407→    if (!data || data.length === 0) {
408→        return { data: [], hasMore: false };
409→    }
410→
411→    const hasMore = data.length > parsedLimit;
412→    const sliced = hasMore ? data.slice(0, parsedLimit) : data;
413→
414→    return { data: sliced.map((story) => decorateStoryMedia(stripEmbedding(story), 'card')), hasMore };
415→};
